  // macros → thresholds efectivos (primário Zabbix, fallback CFG)
  function effThr(macros) {
    var m = {};
    for (var i = 0; i < macros.length; i++) m[macros[i].macro] = parseFloat(macros[i].value);
    function pick(v, fb) { return (v != null && !isNaN(v)) ? v : fb; }
