      for (var a = 0; a < spaceUsed.length; a++) if (vol(spaceUsed[a].name) === v) { used = U.num(spaceUsed[a]); break; }
      for (var b = 0; b < spaceTotal.length; b++) if (vol(spaceTotal[b].name) === v) { tot = U.num(spaceTotal[b]); break; }
