        zbx('item.get', { hostids: [hid], output: ['name', 'lastvalue'], search: { name: ': Total space' } }),
        zbx('usermacro.get', { hostids: [hid], output: ['macro', 'value'] }),
      ]).then(function (res) {
        if (!_isCurrent()) return;
